+	t.Run("invalid domain", func(t *testing.T) {
+		cases := []string{"", "example", "exa mple.com", "bad!domain.com"}
+		for _, in := range cases {
+			if _, err := NormalizeDomain(in); err == nil {
+				t.Fatalf("expected error for %q", in)
+			}
+		}
